input.script:
import { executionsClient } from "@dynatrace-sdk/client-automation";

export default async function main({ execution_id }) {

  // Obtener el contexto de ejecucion via SDK para acceder al evento del trigger
  let execution;
  try {
    execution = await executionsClient.getExecution({ id: execution_id });
  } catch (e) {
    throw new Error(`[EDA-Event-Integration] No se pudo obtener la ejecucion ${execution_id}: ${e.message}`);
  }

  const event = execution.params?.event;

  // Validar campos requeridos antes de continuar
  const requiredFields = ["event.id", "event.name", "event.category"];
  const missing = requiredFields.filter(f => event?.[f] == null || event?.[f] === "");
  if (!event || missing.length > 0) {
    throw new Error(`[EDA-Event-Integration] Campos requeridos ausentes en el evento: ${missing.join(", ")}`);
  }

  // Extraer tag especifico del array entity_tags
  const tags = event["entity_tags"] || [];
  const getTag = (prefix) => {
    const p = prefix.toUpperCase();
    const match = tags.find(t => t.toUpperCase().startsWith(p + ":"));
    return match ? match.split(":").slice(1).join(":") : null;
  };

  const toISO = (ts) => {
    if (!ts) return null;
    const ms = ts < 1e12 ? ts * 1000 : ts;
    return new Date(ms).toISOString();
  };

  return {
      // Identificacion del evento
      event_id:             event["event.id"],
      correlation_id:       event["dt.event.correlation_id"] || null,

      // Que paso
      event_name:           event["event.name"],
      event_description:    event["event.description"] || null,
      event_category:       event["event.category"],
      event_status:         event["event.status"] || null,
      status_transition:    event["event.status_transition"] || null,
      event_start:          toISO(event["event.start"]),
      event_end:            toISO(event["event.end"]),

      // Donde paso
      host_id:              event["dt.entity.host"] || null,
      host_name:            event["dt.entity.host.name"] || event["host.name"] || null,
      host_group_id:        event["dt.host_group.id"] || null,
      host_group_name:      event["dt.entity.host_group.name"] || null,
      source_entity_type:   event["dt.source_entity.type"] || null,
      source_entity:        event["dt.source_entity"] || null,

      // Enrutamiento y contexto operacional (extraido de entity_tags)
      environment:          getTag("ENVIRONMENT"),
      opco:                 getTag("AGO_AXAOPCOTRIGRAM"),
      assignment_group:     getTag("AGO_DEFAULT_ASSIGNMENT_GROUP"),
      platform:             getTag("AGO_AXAPLATFORM"),
      app:                  getTag("AGO_GLOBAL_APP"),
      app_service_id:       getTag("AGO_GLOBAL_APPSERVICEID"),
      patch_environment:    getTag("AGO_AXAPATCHENVIRONMENT"),

      // Control de remediacion
      timeout_minutes:      event["dt.davis.timeout"] || null,
      impact_level:         event["dt.davis.impact_level"] || null,

      // Trazabilidad hacia Dynatrace
      problem_ids:          event["dt.davis.problems"] || []
    };
}
